250	
251	    private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]
252	
253	    static func maskedPayload(_ data: Data) -> String {
254	        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
255	            return "<non-JSON, \(data.count) bytes>"
256	        }
257	        let masked = maskSensitiveFields(json)
258	        guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
259	              let str = String(data: out, encoding: .utf8) else {
260	            return "<serialization failed>"
261	        }
262	        return str
263	    }
264	
265	    static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
266	        var result: [String: Any] = [:]
267	        for (key, value) in dict {
268	            let lower = key.lowercased()
269	            if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
270	                result[key] = "***"
271	            } else if let nested = value as? [String: Any] {
272	                result[key] = maskSensitiveFields(nested)
273	            } else if let array = value as? [[String: Any]] {
274	                result[key] = array.map { maskSensitiveFields($0) }
275	            } else {
276	                result[key] = value
277	            }
278	        }
279	        return result
280	    }
